import React from "react";
import Chart from 'react-apexcharts';

const Dashboard = () => {
  const chartOptions = {
    chart: {
      id: 'sales-line-chart',
    },
    xaxis: {
      categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'],
    },
  };

  const chartSeries = [
    {
      name: 'Sales Line',
      data: [30, 40, 35, 50, 49, 60, 70],
    },
    {
      name: 'Sales Bar',
      data: [20, 30, 25, 40, 35, 50, 60],
    },
  ];

  const barChartOptions = {
    chart: {
      id: 'sales-bar-chart',
    },
    xaxis: {
      categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'],
    },
  };

  const barChartSeries = [
    {
      name: 'Sales',
      data: [20, 30, 25, 40, 35, 50, 60],
    },
  ];

  const pieChartOptions = {
    chart: {
      id: 'inspection-types-chart',
    },
    labels: ['Inspections', 'Follow-ups', 'Re-inspections'],
  };

  const pieChartSeries = [30, 40, 30];

  const lineRaceOptions = {
    chart: {
      id: 'line-race-chart',
    },
    xaxis: {
      categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'],
    },
    series: [
      {
        name: 'Category A',
        data: [10, 20, 30, 40, 50, 60, 70],
      },
      {
        name: 'Category B',
        data: [15, 25, 35, 45, 55, 65, 75],
      },
      {
        name: 'Category C',
        data: [5, 15, 25, 35, 45, 55, 65],
      },
    ],
  };

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h2>Total Sales</h2>
          <p>$100,000</p>
        </div>
        <div className="kpi">
          <h2>Total Inspections</h2>
          <p>250</p>
        </div>
        <div className="kpi">
          <h2>Active Users</h2>
          <p>150</p>
        </div>
      </div>
      <div className="chart-container">
        <div className="chart-item">
          <Chart options={chartOptions} series={chartSeries} type="line" />
        </div>
        <div className="chart-item">
          <Chart options={barChartOptions} series={barChartSeries} type="bar" />
        </div>
        <div className="chart-item">
          <Chart options={pieChartOptions} series={pieChartSeries} type="pie" />
        </div>
        <div className="chart-item">
          <Chart options={lineRaceOptions} series={lineRaceOptions.series} type="line" />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
